import (
	context "context"
	fernclient "github.com/header-auth-environment-variable/fern/client"
	option "github.com/header-auth-environment-variable/fern/option"
)

client := fernclient.NewClient(
	option.WithAPIKey(
		"<YOUR_APIKey>",
	),
)
response, err := client.Service.Getwithbearertoken(
	context.TODO(),
)
